// Title: Event Calendar Agenda View
// Description: Chronological agenda grouped by day - a day header row plus a clean time / dot / title table.

"use client"

import { useMemo } from "react"
import {
  EventCalendarViewContext,
  useEventCalendar,
  useEventCalendarSelector,
  useEventCalendarSettings,
  useEventCalendarViewConfig,
} from "@/components/reui/event-calendar/event-calendar"
import { EventCalendarEvent } from "@/components/reui/event-calendar/event-calendar-event"
import {
  getDayKey,
  getRangeKey,
  toZoned,
  zonedStartOfDay,
} from "@/components/reui/event-calendar/event-calendar-lib"
import type {
  EventCalendarDateRange,
  EventCalendarSegment,
} from "@/components/reui/event-calendar/event-calendar-types"
import { IconStack } from "@/components/reui/icon-stack"
import { mergeProps } from "@base-ui/react/merge-props"
import { useRender } from "@base-ui/react/use-render"
import { addDays, format } from "date-fns"

import { cn } from "@/lib/utils"
import { ScrollArea } from "@/components/ui/scroll-area"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

// The agenda window length is the agendaDayCount SETTING (the store derives
// visibleRange from it); a per-view prop here would silently disagree.
type EventCalendarAgendaViewProps = useRender.ComponentProps<"div">

function EventCalendarAgendaView({
  className,
  render,
  ...props
}: EventCalendarAgendaViewProps) {
  const instance = useEventCalendar()
  const settings = useEventCalendarSettings()
  const viewConfig = useEventCalendarViewConfig()
  const visibleRange = useEventCalendarSelector<
    unknown,
    EventCalendarDateRange
  >((state) => state.visibleRange, {
    isEqual: (a, b) => getRangeKey(a) === getRangeKey(b),
  })
  // Subscribe to event changes via the day-bucket content of the whole range
  useEventCalendarSelector((state) => state.events)

  const days = useMemo(() => {
    const result: Date[] = []
    let cursor = zonedStartOfDay(visibleRange.start, settings.timeZone)
    while (cursor < visibleRange.end) {
      result.push(cursor)
      cursor = zonedStartOfDay(
        addDays(toZoned(cursor, settings.timeZone), 1),
        settings.timeZone
      )
    }
    return result
  }, [visibleRange, settings.timeZone])

  const index = instance.internals.getIndex()
  const groups = days
    .map((day) => ({
      day,
      bucket: index.byDay.get(getDayKey(day, settings.timeZone)),
    }))
    .filter((group) => {
      const total =
        (group.bucket?.allDay.length ?? 0) + (group.bucket?.timed.length ?? 0)
      return total > 0
    })

  const isToday = (day: Date) =>
    getDayKey(day, settings.timeZone) ===
    getDayKey(new Date(), settings.timeZone)

  const native = viewConfig.scrollbars === "native"

  const body = (
    <>
      {groups.length === 0 ? (
        <div
          data-slot="event-calendar-no-events"
          className={cn(
            "flex min-h-72 flex-col items-center justify-center gap-4 py-16",
            viewConfig.classNames?.noEvents
          )}
        >
          {viewConfig.renderNoEvents?.() ?? (
            <>
              <IconStack>
                <IconPlaceholder
                  lucide="CalendarIcon"
                  tabler="IconCalendarEvent"
                  hugeicons="Calendar04Icon"
                  phosphor="CalendarBlankIcon"
                  remixicon="RiCalendarLine"
                  className="size-5"
                  aria-hidden="true"
                />
              </IconStack>
              <span className="text-muted-foreground text-sm">
                {settings.i18n.labels.noEvents}
              </span>
            </>
          )}
        </div>
      ) : (
        // Drop the very last row's bottom border so it does not double up with
        // the calendar container's own bottom border. Targets the last day
        // group's last child (its last agenda item); per-item `border-b` is
        // kept everywhere else, including each day's internal rows.
        <div className="flex flex-col [&>*:last-child>*:last-child]:border-b-0">
          {groups.map(({ day, bucket }) => {
            const items = [...(bucket?.allDay ?? []), ...(bucket?.timed ?? [])]
            const zoned = toZoned(day, settings.timeZone)
            return (
              <div
                key={day.getTime()}
                data-slot="event-calendar-agenda-day"
                data-today={isToday(day) || undefined}
              >
                {/* Group header: weekday (leading) + full date (trailing) */}
                <div
                  data-slot="event-calendar-agenda-day-header"
                  className={cn(
                    "bg-muted/60 sticky top-0 z-10 flex items-baseline justify-between gap-4 border-b px-4 py-2",
                    // The custom ScrollArea's overlay scrollbar (w-2.5 = 10px)
                    // is painted UNDER this sticky, z-10, opaque header, so the
                    // thumb vanishes behind the day bar at the top of the view.
                    // Inset the header by the scrollbar lane so its background
                    // stops before the scrollbar instead of covering it. Native
                    // scrollbars already sit outside the content box, so this
                    // only applies to the custom-scrollbar path.
                    !native && "me-2.5",
                    viewConfig.classNames?.agendaDayHeader
                  )}
                >
                  <span
                    className={cn(
                      "text-foreground font-semibold",
                      isToday(day) && "text-primary"
                    )}
                  >
                    {format(zoned, "EEEE", { locale: settings.locale })}
                  </span>
                  <span className="text-muted-foreground font-medium tabular-nums">
                    {format(zoned, "MMMM d, yyyy", { locale: settings.locale })}
                  </span>
                </div>
                {items.map((segment) => (
                  <EventCalendarAgendaItem
                    key={segment.occurrence.key}
                    segment={segment}
                  />
                ))}
              </div>
            )
          })}
        </div>
      )}
    </>
  )

  const defaultProps = {
    "data-slot": "event-calendar-agenda-view",
    "data-view": "agenda",
    className: cn(
      "flex min-h-0 flex-1 flex-col overflow-hidden border-t",
      viewConfig.classNames?.agendaView,
      className
    ),
    children: native ? (
      <div
        data-slot="scroll-area-viewport"
        data-ec-native-scroll=""
        className="h-full overflow-y-auto"
      >
        {body}
      </div>
    ) : (
      <ScrollArea className="h-full">{body}</ScrollArea>
    ),
  }

  return (
    <EventCalendarViewContext.Provider value={{ view: "agenda" }}>
      {useRender({
        defaultTagName: "div",
        render,
        props: mergeProps<"div">(defaultProps, props),
      })}
    </EventCalendarViewContext.Provider>
  )
}

/**
 * One agenda row: a full-width, selectable table row - time column, color dot,
 * and title (all replaceable via renderAgendaEvent). Clicking selects the
 * event (drag/resize stay off in the agenda).
 */
function EventCalendarAgendaItem({
  segment,
}: {
  segment: EventCalendarSegment
}) {
  const viewConfig = useEventCalendarViewConfig()
  return (
    <EventCalendarEvent
      segment={segment}
      className={cn(
        // read-only list: hover only, no selected/focused styling on click
        "hover:bg-accent/40 gap-3 rounded-none border-b px-4 py-2.5 transition-colors",
        viewConfig.classNames?.agendaItem
      )}
    />
  )
}

export { EventCalendarAgendaView }
export type { EventCalendarAgendaViewProps }

// Title: Event Calendar Content
// Description: Active-view switchboard rendering month, week, day, N-days, or agenda; swappable per view via the components prop.

"use client"

import { type ComponentType, type ReactNode } from "react"
import {
  useEventCalendarSelector,
  useEventCalendarViewConfig,
} from "@/components/reui/event-calendar/event-calendar"
import { EventCalendarAgendaView } from "@/components/reui/event-calendar/event-calendar-agenda-view"
import { EventCalendarMonthView } from "@/components/reui/event-calendar/event-calendar-month-view"
import { EventCalendarResourceView } from "@/components/reui/event-calendar/event-calendar-resource-view"
import {
  EventCalendarDaysView,
  EventCalendarDayView,
  EventCalendarWeekView,
} from "@/components/reui/event-calendar/event-calendar-time-grid"
import type { CalendarView } from "@/components/reui/event-calendar/event-calendar-types"
import { mergeProps } from "@base-ui/react/merge-props"
import { useRender } from "@base-ui/react/use-render"

import { cn } from "@/lib/utils"

const DEFAULT_VIEW_COMPONENTS: Record<CalendarView, ComponentType> = {
  month: EventCalendarMonthView,
  week: EventCalendarWeekView,
  day: EventCalendarDayView,
  days: EventCalendarDaysView,
  agenda: EventCalendarAgendaView,
  resource: EventCalendarResourceView,
}

interface EventCalendarContentProps extends Omit<
  useRender.ComponentProps<"div">,
  "children"
> {
  /** Swap individual view implementations. */
  components?: Partial<Record<CalendarView, ComponentType>>
  /** Replaces the switchboard entirely; read useEventCalendarView() inside. */
  children?: ReactNode
}

function EventCalendarContent({
  className,
  render,
  components,
  children,
  ...props
}: EventCalendarContentProps) {
  const viewConfig = useEventCalendarViewConfig()
  const view = useEventCalendarSelector((state) => state.view)
  const loading = useEventCalendarSelector((state) => state.loading)

  const resolved = {
    ...DEFAULT_VIEW_COMPONENTS,
    ...viewConfig.components,
    ...components,
  }
  const ActiveView = resolved[view]

  const defaultProps = {
    "data-slot": "event-calendar-content",
    "data-view": view,
    "data-loading": loading || undefined,
    className: cn(
      "relative flex min-h-0 min-w-0 flex-1 flex-col",
      "data-loading:pointer-events-none data-loading:opacity-60",
      viewConfig.classNames?.content,
      className
    ),
    children: children ?? <ActiveView />,
  }

  return useRender({
    defaultTagName: "div",
    render,
    props: mergeProps<"div">(defaultProps, props),
  })
}

export { DEFAULT_VIEW_COMPONENTS, EventCalendarContent }
export type { EventCalendarContentProps }

// Title: Event Calendar Dnd
// Description: Custom pointer-event interaction engine - move, resize, and drag-create across month, week, day, and N-day views with live validation.

"use client"

import { useCallback, useMemo } from "react"
import {
  useEventCalendar,
  useEventCalendarViewConfig,
  type EventCalendarInstance,
} from "@/components/reui/event-calendar/event-calendar"
import {
  snapMinutes,
  toZoned,
  zonedStartOfDay,
} from "@/components/reui/event-calendar/event-calendar-lib"
import type {
  EventCalendarProposedUpdate,
  EventCalendarSegment,
} from "@/components/reui/event-calendar/event-calendar-types"
import { addDays, addMinutes, differenceInCalendarDays } from "date-fns"

/**
 * Activation policy (dnd-kit parity where proven):
 * mouse move 5px before a drag starts (below = click), create 4px;
 * touch long-press 250ms with 5px tolerance (movement past tolerance
 * before the delay cancels the drag so taps stay taps).
 */
const EVENT_CALENDAR_ACTIVATION = {
  moveDistancePx: 5,
  createDistancePx: 4,
  touchDelayMs: 250,
  touchTolerancePx: 5,
  autoScrollEdgePx: 48,
  autoScrollMaxStepPx: 15,
} as const

type GestureKind = "move" | "resize-start" | "resize-end" | "create"

interface TimeColumnRect {
  day: Date
  rect: DOMRect
  boundsStartMin: number
  boundsEndMin: number
  resourceId?: string
}

interface DayCellRect {
  day: Date
  rect: DOMRect
}

interface Surface {
  /** Minute-precise day columns (week/day/days) or resource columns. */
  columns: TimeColumnRect[]
  /** Day-precise cells (month grid, all-day row). */
  cells: DayCellRect[]
  viewport: HTMLElement | null
  /**
   * Viewport rect captured ONCE at gesture start. The scroll container does
   * not move on screen while a pointer drag is captured (auto-scroll changes
   * its scrollTop, not its box), so reusing this avoids a per-pointermove
   * getBoundingClientRect - that read forces a synchronous full-document
   * reflow, which is cheap on a bare demo page but ~200ms on a long docs page
   * (big prop tables re-lay-out on every flush), turning drag into a slideshow.
   */
  viewportRect: DOMRect | null
  viewportStartScrollTop: number
  /**
   * Live scrollTop, seeded from the start value and advanced by auto-scroll
   * itself. Tracking it here lets pointerMinutes read a number instead of the
   * DOM `scrollTop` property every move (another forced reflow).
   */
  scrollTop: number
}

/** Module flag so chip onClick can ignore the click that ends a drag. */
let lastGestureEndedAt = 0
function wasRecentDrag(): boolean {
  return performance.now() - lastGestureEndedAt < 250
}

/**
 * A press that started on an event chip. Slot-create clicks consult this so a
 * refused drag (e.g. a locked chip that never registers a gesture) whose
 * trailing native click retargets to the empty grid does NOT open a create
 * dialog. Refreshed on release so it covers long presses; the chip's own
 * click-to-edit is unaffected (only grid slot-clicks check it).
 */
let lastChipPressAt = 0
function markChipPress(): void {
  lastChipPressAt = performance.now()
  window.addEventListener(
    "pointerup",
    () => {
      lastChipPressAt = performance.now()
    },
    { once: true, capture: true }
  )
}
function wasRecentChipPress(): boolean {
  return performance.now() - lastChipPressAt < 300
}

/**
 * Snap a translate offset to the device pixel grid. The cursor-following
 * overlays (carry clone, drop hint) are their own `will-change: transform`
 * compositing layers: the GPU rasterizes their text once and repositions that
 * texture each frame, so a subpixel translate (getBoundingClientRect and raw
 * clientX/Y are routinely fractional) resamples the texture and blurs the
 * text. Rounding each offset to a whole device pixel lands the layer on the
 * grid so glyphs stay crisp, without giving up the per-frame GPU transform.
 */
function snapToPixel(value: number): number {
  const dpr = typeof window !== "undefined" ? window.devicePixelRatio || 1 : 1
  return Math.round(value * dpr) / dpr
}

function collectSurface(
  origin: HTMLElement,
  fallbackRoot?: HTMLElement | null
): Surface {
  // A gesture from a portaled surface (the "+N more" popover) has no calendar
  // ancestor, so fall back to the root the host registered on the instance.
  const root =
    origin.closest<HTMLElement>("[data-slot=event-calendar-time-grid]") ??
    origin.closest<HTMLElement>("[data-slot=event-calendar-resource-view]") ??
    origin.closest<HTMLElement>("[data-slot=event-calendar-month-view]") ??
    origin.closest<HTMLElement>("[data-slot=event-calendar]") ??
    fallbackRoot ??
    null

  const columns: TimeColumnRect[] = []
  const cells: DayCellRect[] = []
  if (root) {
    for (const el of root.querySelectorAll<HTMLElement>("[data-ec-day]")) {
      const day = new Date(Number(el.dataset.ecDay))
      if (el.dataset.ecBoundsStart !== undefined) {
        columns.push({
          day,
          rect: el.getBoundingClientRect(),
          boundsStartMin: Number(el.dataset.ecBoundsStart),
          boundsEndMin: Number(el.dataset.ecBoundsEnd),
          resourceId: el.dataset.ecResource,
        })
      } else {
        cells.push({ day, rect: el.getBoundingClientRect() })
      }
    }
  }
  const viewport =
    root?.querySelector<HTMLElement>("[data-slot=scroll-area-viewport]") ?? null
  const viewportStartScrollTop = viewport?.scrollTop ?? 0
  return {
    columns,
    cells,
    viewport,
    viewportRect: viewport?.getBoundingClientRect() ?? null,
    viewportStartScrollTop,
    scrollTop: viewportStartScrollTop,
  }
}

function findColumn(
  surface: Surface,
  clientX: number
): TimeColumnRect | undefined {
  const scrollAdjusted = surface.columns
  let best: TimeColumnRect | undefined
  for (const col of scrollAdjusted) {
    if (clientX >= col.rect.left && clientX < col.rect.right) return col
    if (!best) best = col
    // clamp to nearest horizontal column
    const bestDist = Math.min(
      Math.abs(clientX - best.rect.left),
      Math.abs(clientX - best.rect.right)
    )
    const dist = Math.min(
      Math.abs(clientX - col.rect.left),
      Math.abs(clientX - col.rect.right)
    )
    if (dist < bestDist) best = col
  }
  return best
}

function findCell(
  surface: Surface,
  x: number,
  y: number
): DayCellRect | undefined {
  return surface.cells.find(
    (cell) =>
      x >= cell.rect.left &&
      x < cell.rect.right &&
      y >= cell.rect.top &&
      y < cell.rect.bottom
  )
}

function pointerMinutes(
  surface: Surface,
  col: TimeColumnRect,
  clientY: number
): number {
  const scrollDelta = surface.scrollTop - surface.viewportStartScrollTop
  const boundsMinutes = col.boundsEndMin - col.boundsStartMin
  const pxPerMinute = col.rect.height / Math.max(1, boundsMinutes)
  const y = clientY - col.rect.top + scrollDelta
  return col.boundsStartMin + y / pxPerMinute
}

interface BeginGestureConfig<TData> {
  instance: EventCalendarInstance<TData>
  kind: GestureKind
  origin: HTMLElement
  startEvent: PointerEvent
  segment?: EventCalendarSegment<TData>
  /** create only */
  createDay?: Date
  createAllDay?: boolean
  /**
   * Consumer classNames for the engine's vanilla-DOM overlays (carry clone,
   * validation hint pill), forwarded by the gestures hook - the engine itself
   * must never import from the React chip module.
   */
  ui?: {
    dragCarry?: string
    dragCarryInvalid?: string
    dropHint?: string
  }
}

/**
 * A move/resize was refused (locked, per-event disabled, or interaction off).
 * Rather than silently swallow the press, track the pointer: once it crosses
 * the activation threshold - i.e. the user genuinely tried to drag - show a
 * not-allowed cursor and broadcast once via onDragBlocked so the consumer can
 * explain it. The calendar picks no message. Fires at most once per gesture.
 */
function beginBlockedGesture<TData>(
  instance: EventCalendarInstance<TData>,
  startEvent: PointerEvent,
  segment: EventCalendarSegment<TData>,
  gesture: "move" | "resize"
) {
  const startX = startEvent.clientX
  const startY = startEvent.clientY
  const activation = {
    ...EVENT_CALENDAR_ACTIVATION,
    ...instance.settings.activation,
  }
  const event = segment.occurrence.event
  const reason: "readOnly" | "disabled" | "interactions-off" = event.readOnly
    ? "readOnly"
    : (gesture === "move" ? event.draggable : event.resizable) === false
      ? "disabled"
      : "interactions-off"
  let activated = false
  const onMove = (e: PointerEvent) => {
    if (activated) return
    if (
      Math.hypot(e.clientX - startX, e.clientY - startY) <
      activation.moveDistancePx
    ) {
      return
    }
    activated = true
    document.body.style.cursor = "not-allowed"
    // body class alongside the inline cursor so consumer CSS can restyle or
    // detect the blocked-drag state (mirrors "ec-dragging")
    document.body.classList.add("ec-drag-blocked")
    instance.settings.onDragBlocked?.(segment.occurrence, { gesture, reason })
  }
  const cleanup = () => {
    window.removeEventListener("pointermove", onMove)
    window.removeEventListener("pointerup", cleanup)
    window.removeEventListener("pointercancel", cleanup)
    if (activated) {
      document.body.style.cursor = ""
      document.body.classList.remove("ec-drag-blocked")
      // the pointer travelled: suppress the trailing click so the event's own
      // dialog does not open on top of the rejection message
      lastGestureEndedAt = performance.now()
    }
  }
  window.addEventListener("pointermove", onMove)
  window.addEventListener("pointerup", cleanup)
  window.addEventListener("pointercancel", cleanup)
}

function beginGesture<TData>(config: BeginGestureConfig<TData>) {
  const { instance, kind, origin, startEvent, segment, ui } = config
  const { settings, internals, api } = instance
  const timeZone = settings.timeZone
  const snap = settings.snapDuration
  // per-calendar tuning shallow-merged over the module defaults
  const activation = { ...EVENT_CALENDAR_ACTIVATION, ...settings.activation }
  const startX = startEvent.clientX
  const startY = startEvent.clientY

  let active = kind.startsWith("resize") // resize activates immediately
  let surface: Surface | null = active
    ? collectSurface(origin, internals.getRootEl())
    : null
  let rafScroll: number | null = null
  let lastProposalKey = ""
  let touchTimer: ReturnType<typeof setTimeout> | null = null
  let hintEl: HTMLDivElement | null = null
  let lastValid = true
  // Drag-create anchor minute, frozen at the first proposal: re-deriving it
  // from the stale startY client coordinate + the CURRENT scroll delta would
  // make the anchor drift with auto-scroll instead of staying pinned.
  let createAnchorMin: number | null = null
  let lastPointer: PointerEvent = startEvent
  const isTouch = startEvent.pointerType === "touch"

  const occurrence = segment?.occurrence
  const isBar = occurrence
    ? occurrence.allDay ||
      occurrence.end.getTime() - occurrence.start.getTime() >
        24 * 60 * 60 * 1000
    : false

  // Preserve the grab offset so the event does not jump to the pointer
  let grabOffsetMin = 0

  const activationDistance =
    kind === "create" ? activation.createDistancePx : activation.moveDistancePx

  // Each gesture keeps its own cursor: a resize must stay ns/ew-resize for
  // the whole drag (flipping to grabbing reads as a move) - vertical for
  // timed blocks, horizontal for day-granular bars. Moves grab.
  const gestureCursor = kind.startsWith("resize")
    ? isBar
      ? "ew-resize"
      : "ns-resize"
    : "grabbing"
  const setBodyDragging = (on: boolean, invalid = false) => {
    document.body.classList.toggle("ec-dragging", on)
    document.body.style.cursor = on
      ? invalid
        ? "not-allowed"
        : gestureCursor
      : ""
    document.body.style.userSelect = on ? "none" : ""
    if (!on) document.body.style.removeProperty("-webkit-user-select")
  }

  const activate = () => {
    if (active) return
    active = true
    surface = collectSurface(origin, internals.getRootEl())
    if (kind === "move" && occurrence && surface.columns.length > 0 && !isBar) {
      const col = findColumn(surface, startX)
      if (col) {
        const startMin =
          (occurrence.start.getTime() -
            zonedStartOfDay(occurrence.start, timeZone).getTime()) /
          60000
        grabOffsetMin = pointerMinutes(surface, col, startY) - startMin
      }
    }
    setBodyDragging(true)
    createCarry()
  }

  const computeProposal = (
    e: PointerEvent
  ): {
    start: Date
    end: Date
    allDay: boolean
    dayGranular?: boolean
    resourceId?: string
  } | null => {
    if (!surface) return null

    // ---- create: select a slot range
    if (kind === "create") {
      if (config.createAllDay || surface.columns.length === 0) {
        const anchor = zonedStartOfDay(config.createDay!, timeZone)
        const cell = findCell(surface, e.clientX, e.clientY)
        const target = cell ? zonedStartOfDay(cell.day, timeZone) : anchor
        const start = anchor <= target ? anchor : target
        const end = addDays(anchor <= target ? target : anchor, 1)
        return { start, end, allDay: true, dayGranular: true }
      }
      const col = findColumn(surface, startX)
      if (!col) return null
      if (createAnchorMin === null) {
        createAnchorMin = snapMinutes(
          pointerMinutes(surface, col, startY),
          snap
        )
      }
      const anchorMin = createAnchorMin
      const curMin = snapMinutes(pointerMinutes(surface, col, e.clientY), snap)
      const lo = Math.max(col.boundsStartMin, Math.min(anchorMin, curMin))
      const hi = Math.min(
        col.boundsEndMin,
        Math.max(anchorMin, curMin, lo + snap)
      )
      const dayStart = zonedStartOfDay(col.day, timeZone)
      return {
        start: addMinutes(dayStart, lo),
        end: addMinutes(dayStart, hi),
        allDay: false,
        resourceId: col.resourceId,
      }
    }

    if (!occurrence) return null
    const durationMs = occurrence.end.getTime() - occurrence.start.getTime()

    // ---- day-granularity: month cells and bars in the all-day row
    const overCell = findCell(surface, e.clientX, e.clientY)

    // A timed event dropped on the all-day lane (a day cell inside a surface
    // that also has time columns) converts to a full-day event on that day.
    if (
      kind === "move" &&
      !isBar &&
      surface.columns.length > 0 &&
      overCell !== undefined
    ) {
      const targetDay = zonedStartOfDay(overCell.day, timeZone)
      return {
        start: targetDay,
        end: addDays(targetDay, 1),
        allDay: true,
        dayGranular: true,
      }
    }

    const useCells =
      surface.columns.length === 0 || (isBar && overCell !== undefined)

    if (useCells) {
      const cell = overCell ?? findCell(surface, startX, startY)
      if (!cell) return null
      const targetDay = zonedStartOfDay(cell.day, timeZone)
      if (kind === "move") {
        const originDay = zonedStartOfDay(occurrence.start, timeZone)
        const delta = differenceInCalendarDays(targetDay, originDay)
        const start = addDays(toZoned(occurrence.start, timeZone), delta)
        return {
          start,
          end: new Date(start.getTime() + durationMs),
          allDay: occurrence.allDay,
          dayGranular: true,
        }
      }
      // bar edge resize: day granularity
      if (kind === "resize-start") {
        const time =
          occurrence.start.getTime() -
          zonedStartOfDay(occurrence.start, timeZone).getTime()
        const start = new Date(targetDay.getTime() + time)
        if (start >= occurrence.end) return null
        return {
          start,
          end: occurrence.end,
          allDay: occurrence.allDay,
          dayGranular: true,
        }
      }
      const time = occurrence.allDay
        ? 0
        : occurrence.end.getTime() -
          zonedStartOfDay(occurrence.end, timeZone).getTime()
      const end = occurrence.allDay
        ? addDays(targetDay, 1)
        : new Date(addDays(targetDay, time > 0 ? 0 : 1).getTime() + time)
      if (end <= occurrence.start) return null
      return {
        start: occurrence.start,
        end,
        allDay: occurrence.allDay,
        dayGranular: true,
      }
    }

    // ---- minute-granularity: time-grid columns
    const col = findColumn(surface, e.clientX)
    if (!col) return null
    const dayStart = zonedStartOfDay(col.day, timeZone)
    const rawMin = pointerMinutes(surface, col, e.clientY)

    if (kind === "move") {
      const newStartMin = snapMinutes(rawMin - grabOffsetMin, snap)
      const durationMin = Math.round(durationMs / 60000)
      const clamped = Math.min(
        Math.max(newStartMin, col.boundsStartMin),
        col.boundsEndMin - durationMin
      )
      const start = addMinutes(dayStart, clamped)
      return {
        start,
        end: new Date(start.getTime() + durationMs),
        allDay: false,
        resourceId: col.resourceId,
      }
    }

    const min = snapMinutes(rawMin, snap)
    // Both endpoints expressed in the POINTED column's day coordinates.
    // Anchoring each endpoint to its OWN day breaks cross-midnight events:
    // a 23:30 pointer in the start day's column would apply 1410 minutes to
    // the end's next-day anchor and jump the end a full day late (and a
    // midnight-ending event computes occEndMin 0 against its own day).
    const occStartMinInCol = Math.round(
      (occurrence.start.getTime() - dayStart.getTime()) / 60000
    )
    const occEndMinInCol = Math.round(
      (occurrence.end.getTime() - dayStart.getTime()) / 60000
    )
    if (kind === "resize-start") {
      const clamped = Math.min(
        Math.max(min, col.boundsStartMin),
        Math.min(occEndMinInCol - snap, col.boundsEndMin)
      )
      const start = addMinutes(dayStart, clamped)
      if (start >= occurrence.end) return null
      return { start, end: occurrence.end, allDay: false }
    }
    const clamped = Math.max(
      Math.min(min, col.boundsEndMin),
      Math.max(occStartMinInCol + snap, col.boundsStartMin)
    )
    const end = addMinutes(dayStart, clamped)
    if (end <= occurrence.start) return null
    return { start: occurrence.start, end, allDay: false }
  }

  const applyProposal = (e: PointerEvent) => {
    const proposal = computeProposal(e)
    if (!proposal) return
    const key = `${proposal.start.getTime()}-${proposal.end.getTime()}-${proposal.allDay}-${proposal.resourceId ?? ""}`
    if (key === lastProposalKey) return
    lastProposalKey = key

    if (kind === "create") {
      const draft = { ...proposal, view: instance.getState().view }
      if (settings.canSelectSlot && !settings.canSelectSlot(draft)) return
      internals.setSlotDraft(draft)
      return
    }
    const update: EventCalendarProposedUpdate<TData> = {
      event: occurrence!.event,
      occurrence: occurrence!,
      ...proposal,
      source: kind as "drag" | "resize-start" | "resize-end",
    }
    if (kind === "move") update.source = "drag"
    const valid = settings.canDropEvent ? settings.canDropEvent(update) : true
    lastValid = valid
    setBodyDragging(true, !valid)
    internals.setDrag({
      kind: kind === "move" ? "move" : (kind as "resize-start" | "resize-end"),
      occurrence: occurrence!,
      proposedStart: proposal.start,
      proposedEnd: proposal.end,
      proposedAllDay: proposal.allDay,
      proposedDayGranular: proposal.dayGranular ?? false,
      proposedResourceId: proposal.resourceId,
      valid,
    })
  }

  // Cursor-attached carry clone for MOVE gestures: the event travels freely
  // with the pointer, like an absolutely positioned overlay, while the
  // in-grid ghost renders only a faint dashed placeholder at the snapped
  // drop slot (EVENT_CALENDAR_GHOST.move). Vanilla DOM: cloned once at
  // activation, transformed per pointermove, zero React work per frame.
  let carryEl: HTMLDivElement | null = null
  let carryDX = 0
  let carryDY = 0
  const CARRY_CLASS =
    "bg-background pointer-events-none fixed top-0 left-0 z-100 overflow-hidden rounded-sm opacity-90 shadow-md will-change-transform" +
    (ui?.dragCarry ? " " + ui.dragCarry : "")
  const CARRY_INVALID_CLASS =
    `${CARRY_CLASS} ring-destructive/60 ring-1` +
    (ui?.dragCarryInvalid ? " " + ui.dragCarryInvalid : "")

  const createCarry = () => {
    if (kind !== "move") return
    const chip =
      origin.closest<HTMLElement>("[data-slot=event-calendar-event]") ?? origin
    const rect = chip.getBoundingClientRect()
    // The clone is re-parented to <body>, escaping the calendar's inherited
    // font-size, so copy the source chip's resolved type - this keeps the carry
    // matching the grid at any consumer text scale (e.g. root text-sm).
    const chipFont = getComputedStyle(chip)
    carryDX = startX - rect.left
    carryDY = startY - rect.top
    carryEl = document.createElement("div")
    carryEl.setAttribute("data-slot", "event-calendar-drag-carry")
    carryEl.setAttribute("aria-hidden", "true")
    carryEl.className = CARRY_CLASS
    carryEl.style.width = `${rect.width}px`
    carryEl.style.height = `${rect.height}px`
    carryEl.style.fontSize = chipFont.fontSize
    carryEl.style.lineHeight = chipFont.lineHeight
    carryEl.style.transform = `translate3d(${snapToPixel(rect.left)}px, ${snapToPixel(rect.top)}px, 0)`
    const clone = chip.cloneNode(true) as HTMLElement
    clone.removeAttribute("data-dragging")
    clone.style.width = "100%"
    clone.style.height = "100%"
    carryEl.appendChild(clone)
    document.body.appendChild(carryEl)
  }

  const positionCarry = (e: PointerEvent) => {
    if (!carryEl) return
    carryEl.style.transform = `translate3d(${snapToPixel(e.clientX - carryDX)}px, ${snapToPixel(e.clientY - carryDY)}px, 0)`
    const cls = lastValid ? CARRY_CLASS : CARRY_INVALID_CLASS
    if (carryEl.className !== cls) carryEl.className = cls
  }

  // Cursor-following validation hint, visible ONLY while the proposal is
  // rejected (canDropEvent / bounds). Vanilla DOM: zero React work per frame;
  // pairs with the not-allowed cursor and the ghost's destructive marking.
  const updateHint = (e: PointerEvent) => {
    if (lastValid || !active) {
      hintEl?.remove()
      hintEl = null
      return
    }
    if (!hintEl) {
      hintEl = document.createElement("div")
      hintEl.setAttribute("data-slot", "event-calendar-drop-hint")
      // physical left-0 anchor: translate3d positions in physical clientX
      // coordinates, so a logical start-0 anchor would fling it off-screen
      // in RTL documents
      hintEl.className =
        "bg-background text-destructive border-destructive/40 pointer-events-none fixed top-0 left-0 z-100 rounded-md border px-2 py-0.5 text-xs font-medium shadow-sm" +
        (ui?.dropHint ? " " + ui.dropHint : "")
      hintEl.textContent = settings.i18n.labels.dropNotAllowed
      document.body.appendChild(hintEl)
    }
    hintEl.style.transform = `translate3d(${snapToPixel(e.clientX + 12)}px, ${snapToPixel(e.clientY + 16)}px, 0)`
  }

  const autoScroll = (e: PointerEvent) => {
    // Cached rect (see Surface.viewportRect) - never getBoundingClientRect per
    // move; the box is stable while the pointer is captured.
    const rect = surface?.viewportRect
    if (!surface?.viewport || !rect) return
    const edge = activation.autoScrollEdgePx
    const step = activation.autoScrollMaxStepPx
    let delta = 0
    if (e.clientY < rect.top + edge) {
      delta = -step * ((rect.top + edge - e.clientY) / edge)
    } else if (e.clientY > rect.bottom - edge) {
      delta = step * ((e.clientY - (rect.bottom - edge)) / edge)
    }
    if (rafScroll) cancelAnimationFrame(rafScroll)
    if (delta !== 0) {
      const tick = () => {
        // Write-then-readback: the browser clamps scrollTop at the scroll
        // extent, so mirror only the APPLIED delta - otherwise parking the
        // pointer in the edge zone at the limit keeps inflating the tracked
        // value past reality and poisons every later minute mapping. When
        // parked (nothing applied), stop the loop; the next pointermove
        // restarts it.
        const before = surface!.viewport!.scrollTop
        surface!.viewport!.scrollTop = before + delta
        const applied = surface!.viewport!.scrollTop - before
        if (applied === 0) return
        // keep the tracked scrollTop in step so pointerMinutes stays a pure
        // number read (no DOM scrollTop, no forced reflow)
        surface!.scrollTop += applied
        applyProposal(e)
        rafScroll = requestAnimationFrame(tick)
      }
      rafScroll = requestAnimationFrame(tick)
    }
  }

  const cleanup = () => {
    window.removeEventListener("pointermove", onPointerMove)
    window.removeEventListener("pointerup", onPointerUp)
    window.removeEventListener("pointercancel", onCancel)
    window.removeEventListener("keydown", onKeyDown, true)
    if (rafScroll) cancelAnimationFrame(rafScroll)
    if (touchTimer) clearTimeout(touchTimer)
    hintEl?.remove()
    hintEl = null
    carryEl?.remove()
    carryEl = null
    setBodyDragging(false)
  }

  const cancel = () => {
    cleanup()
    if (active) {
      lastGestureEndedAt = performance.now()
      internals.setDrag(null)
      internals.setSlotDraft(null)
    }
  }

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      e.stopPropagation()
      cancel()
    }
  }

  const onPointerMove = (e: PointerEvent) => {
    lastPointer = e
    if (!active) {
      const distance = Math.hypot(e.clientX - startX, e.clientY - startY)
      if (isTouch) {
        // Long-press pending: moving past tolerance means scroll, not drag
        if (distance > activation.touchTolerancePx) cancel()
        return
      }
      if (distance < activationDistance) return
      activate()
    }
    applyProposal(e)
    autoScroll(e)
    updateHint(e)
    positionCarry(e)
  }

  const onPointerUp = (e: PointerEvent) => {
    cleanup()
    if (!active) return
    lastGestureEndedAt = performance.now()

    const state = instance.getState()
    if (kind === "create") {
      const draft = state.slotDraft
      internals.setSlotDraft(null)
      if (draft) {
        api.select({
          slot: { start: draft.start, end: draft.end, allDay: draft.allDay },
        })
        settings.onSelectSlot?.(draft)
      }
      return
    }
    const drag = state.drag
    internals.setDrag(null)
    if (!drag || !occurrence) return
    const unchanged =
      drag.proposedStart.getTime() === occurrence.start.getTime() &&
      drag.proposedEnd.getTime() === occurrence.end.getTime() &&
      (drag.proposedResourceId === undefined ||
        drag.proposedResourceId === occurrence.event.resourceId)
    if (unchanged) return
    // Commit through the one validation funnel; consumer reject = automatic
    // revert because the calendar never mutated during the gesture.
    void e
    internals.applyProposedUpdate({
      event: occurrence.event,
      occurrence,
      start: drag.proposedStart,
      end: drag.proposedEnd,
      allDay: drag.proposedAllDay,
      resourceId: drag.proposedResourceId,
      source:
        kind === "move" ? "drag" : (kind as "resize-start" | "resize-end"),
    })
  }

  const onCancel = () => cancel()

  window.addEventListener("pointermove", onPointerMove)
  window.addEventListener("pointerup", onPointerUp)
  window.addEventListener("pointercancel", onCancel)
  window.addEventListener("keydown", onKeyDown, true)

  // Touch: long-press activation (movement past tolerance cancels above)
  if (isTouch && !active) {
    touchTimer = setTimeout(() => {
      activate()
      applyProposal(lastPointer)
    }, activation.touchDelayMs)
  }
}

/** Per-chip / per-surface pointer gesture wiring. */
function useEventCalendarGestures<TData = unknown>() {
  const instance = useEventCalendar<TData>()
  // Overlay classNames bridged from React config into the vanilla-DOM engine
  // (which must never import from the chip module - circular).
  const { classNames } = useEventCalendarViewConfig<TData>()
  const ui = useMemo(
    () => ({
      dragCarry: classNames?.dragCarry,
      dragCarryInvalid: classNames?.dragCarryInvalid,
      dropHint: classNames?.dropHint,
    }),
    [classNames]
  )

  const canDrag = useCallback(
    (segment: EventCalendarSegment<TData>) => {
      const { interactions } = instance.getState()
      const event = segment.occurrence.event
      return interactions.drag && !event.readOnly && event.draggable !== false
    },
    [instance]
  )

  const canResize = useCallback(
    (segment: EventCalendarSegment<TData>) => {
      const { interactions } = instance.getState()
      const event = segment.occurrence.event
      return interactions.resize && !event.readOnly && event.resizable !== false
    },
    [instance]
  )

  const beginMove = useCallback(
    (e: React.PointerEvent, segment: EventCalendarSegment<TData>) => {
      if (e.button !== 0) return
      if (!canDrag(segment)) {
        // refused, but still give feedback + broadcast on a real drag attempt
        beginBlockedGesture(instance, e.nativeEvent, segment, "move")
        return
      }
      beginGesture({
        instance,
        kind: "move",
        origin: e.currentTarget as HTMLElement,
        startEvent: e.nativeEvent,
        segment,
        ui,
      })
    },
    [instance, canDrag, ui]
  )

  const beginResize = useCallback(
    (
      e: React.PointerEvent,
      segment: EventCalendarSegment<TData>,
      edge: "start" | "end"
    ) => {
      if (e.button !== 0) return
      if (!canResize(segment)) {
        e.stopPropagation()
        beginBlockedGesture(instance, e.nativeEvent, segment, "resize")
        return
      }
      e.stopPropagation()
      e.preventDefault()
      beginGesture({
        instance,
        kind: edge === "start" ? "resize-start" : "resize-end",
        origin: e.currentTarget as HTMLElement,
        startEvent: e.nativeEvent,
        segment,
        ui,
      })
    },
    [instance, canResize, ui]
  )

  const beginCreate = useCallback(
    (e: React.PointerEvent, day: Date, allDay: boolean) => {
      if (e.button !== 0) return
      if (!instance.getState().interactions.selectSlot) return
      beginGesture({
        instance,
        kind: "create",
        origin: e.currentTarget as HTMLElement,
        startEvent: e.nativeEvent,
        createDay: day,
        createAllDay: allDay,
        ui,
      })
    },
    [instance, ui]
  )

  return { beginMove, beginResize, beginCreate, canDrag, canResize }
}

export {
  EVENT_CALENDAR_ACTIVATION,
  markChipPress,
  useEventCalendarGestures,
  wasRecentChipPress,
  wasRecentDrag,
}

// Title: Event Calendar Event
// Description: The reusable event chip/bar/block - selection, clicks, drag + resize wiring, and the consumer render slot.

"use client"

import {
  createContext,
  useContext,
  useMemo,
  type CSSProperties,
  type ReactNode,
} from "react"
import {
  useEventCalendar,
  useEventCalendarSelector,
  useEventCalendarViewConfig,
  useEventCalendarViewContext,
} from "@/components/reui/event-calendar/event-calendar"
import {
  markChipPress,
  useEventCalendarGestures,
  wasRecentDrag,
} from "@/components/reui/event-calendar/event-calendar-dnd"
import {
  spansMultipleDays,
  toZoned,
  zonedStartOfDay,
} from "@/components/reui/event-calendar/event-calendar-lib"
import type {
  EventCalendarOccurrence,
  EventCalendarSegment,
} from "@/components/reui/event-calendar/event-calendar-types"
import { mergeProps } from "@base-ui/react/merge-props"
import { useRender } from "@base-ui/react/use-render"
import { addDays, format } from "date-fns"

import { cn } from "@/lib/utils"
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

/**
 * Effective Tailwind palette presets for event colors; every entry works on
 * light and dark surfaces through the chip's alpha background + accent border.
 */
const EVENT_CALENDAR_COLORS: Array<{ name: string; value: string }> = [
  { name: "Blue", value: "var(--color-blue-500)" },
  { name: "Emerald", value: "var(--color-emerald-500)" },
  { name: "Violet", value: "var(--color-violet-500)" },
  { name: "Rose", value: "var(--color-rose-500)" },
  { name: "Amber", value: "var(--color-amber-500)" },
  { name: "Cyan", value: "var(--color-cyan-500)" },
  { name: "Orange", value: "var(--color-orange-500)" },
  { name: "Pink", value: "var(--color-pink-500)" },
  { name: "Teal", value: "var(--color-teal-500)" },
  { name: "Indigo", value: "var(--color-indigo-500)" },
]

/**
 * Standardized drag-ghost surface treatment, shared verbatim by every view
 * (month, week/day/N-days, resource). One visual language for interactions:
 * - move: the event is CARRIED FREELY - a cursor-attached full clone (built
 *   by the dnd engine, data-slot=event-calendar-drag-carry) travels with the
 *   pointer; the in-grid ghost is only this faint dashed placeholder marking
 *   the snapped drop slot. The source stays dimmed in place.
 * - resize: the event is STRETCHED - the chip itself at the proposed extent
 *   with a dashed boundary instead of solid (slight indicator, no elevation).
 * - invalid: destructive tint on the placeholder / dashed clone; the engine
 *   adds the not-allowed cursor, a destructive ring on the carry clone, and
 *   a cursor-following validation hint.
 */
const EVENT_CALENDAR_GHOST = {
  move: "rounded-sm border border-dashed border-(--ec-event-color)/50 bg-(--ec-event-color)/8",
  resize:
    "rounded-sm border border-dashed border-(--ec-event-color)/70 overflow-hidden",
  invalid: "border-destructive/70 bg-destructive/10",
  invalidResize: "border-destructive/70",
  /** Applied to the clone inside an invalid resize ghost. */
  invalidContent: "opacity-60",
} as const

/**
 * Fade-out truncation for stacked timed blocks: squeezed cascade columns
 * hard-clip titles into a mash of adjacent glyphs; a right-edge mask fade
 * reads cleaner than an ellipsis at those tiny widths. The mask applies ONLY
 * below a 10rem container width - mask-image forces text off subpixel
 * antialiasing onto a grayscale raster layer, so masking every wide chip
 * makes the whole grid read bolder/blurry and shimmer while the window
 * resizes. Wide chips keep a plain ellipsis. Consumer renderEvent content
 * can import and reuse it.
 */
const EVENT_CALENDAR_FADE_TRUNCATE =
  "w-full truncate @max-[10rem]:text-clip @max-[10rem]:[mask-image:linear-gradient(to_right,#000_calc(100%-0.75rem),transparent)] @max-[10rem]:rtl:[mask-image:linear-gradient(to_left,#000_calc(100%-0.75rem),transparent)]"

interface EventCalendarChipContextValue<TData = unknown> {
  occurrence: EventCalendarOccurrence<TData>
  segment: EventCalendarSegment<TData>
  isDragging: boolean
  isSelected: boolean
}

const EventCalendarChipContext =
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  createContext<EventCalendarChipContextValue<any> | null>(null)

/** The chip's subject; usable inside renderEvent content and chip children. */
function useEventCalendarEventChip<
  TData = unknown,
>(): EventCalendarChipContextValue<TData> {
  const ctx = useContext(EventCalendarChipContext)
  if (!ctx) {
    throw new Error(
      "useEventCalendarEventChip must be used within <EventCalendarEvent>"
    )
  }
  return ctx as EventCalendarChipContextValue<TData>
}

interface EventCalendarEventProps<TData = unknown> extends Omit<
  useRender.ComponentProps<"button">,
  "children"
> {
  segment: EventCalendarSegment<TData>
  /** Replaces the default chip CONTENT; the wrapper stays calendar-owned. */
  children?: ReactNode
  /**
   * Static drag clone: renders the chip exactly as-is but inert - no gestures,
   * resize handles, selection/drag state, focus, or pointer events. Used for
   * the full-fidelity ghost that tracks the proposed slot during a move.
   */
  preview?: boolean
}

/**
 * The one interactive event element used by every view. The wrapper owns
 * positioning hooks, a11y, selection, drag/resize listeners, and data
 * attributes; content comes from children, the root renderEvent override,
 * or the built-in default.
 */
function EventCalendarEvent<TData = unknown>({
  segment,
  className,
  render,
  children,
  preview = false,
  ...props
}: EventCalendarEventProps<TData>) {
  const instance = useEventCalendar<TData>()
  const viewConfig = useEventCalendarViewConfig<TData>()
  const { view } = useEventCalendarViewContext()
  const gestures = useEventCalendarGestures<TData>()
  const { settings } = instance
  const occurrence = segment.occurrence
  const event = occurrence.event

  const isSelectedRaw = useEventCalendarSelector<TData, boolean>(
    (state) => state.selection.eventKeys.includes(occurrence.key),
    { calendar: instance }
  )
  const isDraggingRaw = useEventCalendarSelector<TData, boolean>(
    (state) => state.drag?.occurrence.key === occurrence.key,
    { calendar: instance }
  )
  // reactive, unlike gestures.canResize: api.setInteractions({ resize })
  // must add/remove the handles without waiting for an unrelated re-render
  const resizeOn = useEventCalendarSelector<TData, boolean>(
    (state) => state.interactions.resize,
    { calendar: instance }
  )
  // A preview clone must never inherit the source's selected/dragging state
  // (the drag key matches, which would dim the clone itself).
  const isSelected = preview ? false : isSelectedRaw
  const isDragging = preview ? false : isDraggingRaw

  const isBar = occurrence.allDay || spansMultipleDays(occurrence)
  const inTimeGrid =
    view === "week" || view === "day" || view === "days" || view === "resource"
  const interactive = view !== "agenda" && !preview
  const timedBlock = inTimeGrid && !isBar
  const horizontalBar = isBar && !inTimeGrid
  // >= compactEventMinutes renders the stacked (title over time) layout;
  // squeezed cascade columns there fade-truncate instead of hard-clipping
  // into neighbors
  const stackedBlock =
    timedBlock &&
    (segment.endMin ?? 0) - (segment.startMin ?? 0) >=
      viewConfig.compactEventMinutes

  const defaultContent = (
    <>
      {/* leading color dot for single-row chips (month cells, all-day bars);
          time-grid blocks read their color from the tinted surface instead -
          in the stacked layout a dot would sit alone on the first line */}
      {!timedBlock && (
        <span
          aria-hidden
          data-slot="event-calendar-event-dot"
          // -me-0.5 tightens just the dot-to-title gap (the chip keeps gap-1.5
          // between the title and the trailing time)
          className="-me-0.5 size-1.5 shrink-0 rounded-full bg-(--ec-event-color)"
        />
      )}
      {occurrence.isRecurring && (
        <IconPlaceholder
          lucide="RepeatIcon"
          tabler="IconRepeat"
          hugeicons="RepeatIcon"
          phosphor="RepeatIcon"
          remixicon="RiRepeatLine"
          className="size-2.5 shrink-0 opacity-70"
          aria-hidden="true"
        />
      )}
      <span
        className={cn(
          "font-medium",
          stackedBlock ? EVENT_CALENDAR_FADE_TRUNCATE : "truncate"
        )}
      >
        {event.title}
      </span>
      {/* month cells are narrow: a compact never-shrinking start time keeps
          the title readable; grid views show the full range */}
      {!occurrence.allDay &&
        segment.isStart &&
        (view === "month" ? (
          <span className="text-muted-foreground shrink-0">
            {format(
              toZoned(occurrence.start, settings.timeZone),
              settings.i18n.formats.eventTime,
              { locale: settings.locale }
            )}
          </span>
        ) : (
          <span
            className={cn(
              "text-muted-foreground hidden @[8rem]:inline",
              stackedBlock ? EVENT_CALENDAR_FADE_TRUNCATE : "truncate"
            )}
          >
            {settings.i18n.functions.formatEventTime(
              toZoned(occurrence.start, settings.timeZone),
              toZoned(occurrence.end, settings.timeZone),
              occurrence.allDay
            )}
          </span>
        ))}
    </>
  )

  // Agenda time text is per-day for multi-day events: the first day reads
  // "From 9:00 AM", middle days "All day", the last day "Until 5:00 PM".
  // Boundaries derive from the occurrence vs segment.day (never the packing
  // flags - lane merging rewrites those on shared segment objects).
  const agendaTimeText = (() => {
    if (view !== "agenda") return ""
    if (occurrence.allDay) return settings.i18n.labels.allDay
    const dayStart = zonedStartOfDay(segment.day, settings.timeZone)
    const dayEnd = addDays(toZoned(dayStart, settings.timeZone), 1)
    const startsBefore = occurrence.start < dayStart
    const endsAfter = occurrence.end > dayEnd
    if (startsBefore && endsAfter) return settings.i18n.labels.allDay
    if (endsAfter) {
      return settings.i18n.labels.timeFrom(
        format(
          toZoned(occurrence.start, settings.timeZone),
          settings.i18n.formats.eventTime,
          { locale: settings.locale }
        )
      )
    }
    if (startsBefore) {
      return settings.i18n.labels.timeUntil(
        format(
          toZoned(occurrence.end, settings.timeZone),
          settings.i18n.formats.eventTime,
          { locale: settings.locale }
        )
      )
    }
    return settings.i18n.functions.formatEventTime(
      toZoned(occurrence.start, settings.timeZone),
      toZoned(occurrence.end, settings.timeZone),
      false
    )
  })()

  // Agenda default row: time column, color-dot badge, plain title
  const agendaDefaultContent = (
    <>
      <span className="text-muted-foreground w-40 shrink-0 truncate tabular-nums">
        {agendaTimeText}
      </span>
      <span
        aria-hidden
        data-slot="event-calendar-agenda-dot"
        className="size-2 shrink-0 rounded-full bg-(--ec-event-color)"
      />
      <span className="truncate text-sm">{event.title}</span>
      {occurrence.isRecurring && (
        <IconPlaceholder
          lucide="RepeatIcon"
          tabler="IconRepeat"
          hugeicons="RepeatIcon"
          phosphor="RepeatIcon"
          remixicon="RiRepeatLine"
          className="text-muted-foreground size-2.5 shrink-0"
          aria-hidden="true"
        />
      )}
    </>
  )

  // Custom chip content is memoized so a drag - which re-renders the lane on
  // every pointer move - never re-invokes the consumer's renderEvent per frame.
  // The element stays referentially stable across those re-renders, so React
  // skips the custom subtree and it doesn't flicker; on drop only the moved
  // chip's inputs change and recompute. Deps are exactly renderProps' inputs
  // plus the render fns (all stable during an internal drag).
  const customContent = useMemo(() => {
    const renderProps = { occurrence, segment, view, isDragging, isSelected }
    return view === "agenda"
      ? viewConfig.renderAgendaEvent?.(renderProps)
      : viewConfig.renderEvent?.(renderProps)
  }, [
    occurrence,
    segment,
    view,
    isDragging,
    isSelected,
    viewConfig.renderAgendaEvent,
    viewConfig.renderEvent,
  ])
  const content =
    children ??
    customContent ??
    (view === "agenda" ? agendaDefaultContent : defaultContent)

  const timeLabel = settings.i18n.functions.formatEventTime(
    toZoned(occurrence.start, settings.timeZone),
    toZoned(occurrence.end, settings.timeZone),
    occurrence.allDay
  )
  // native hover tooltip text; a consumer formatter returning undefined
  // drops the title attribute entirely (e.g. when it renders its own tooltip)
  const label = settings.i18n.functions.formatEventLabel
    ? settings.i18n.functions.formatEventLabel(event.title, timeLabel)
    : `${event.title}, ${timeLabel}`

  // Optional styled tooltip on hover / keyboard focus (viewConfig.eventTooltip,
  // default off). When on, the native title is dropped so the two never stack;
  // a preview clone never gets one. Content defaults to the label and can be
  // overridden with renderEventTooltip - a falsy result (null/undefined, or
  // the `false`/"" that `cond && <node>` yields) falls back to the label, and
  // an empty label (i18n opt-out) leaves no content so the tooltip is skipped.
  const tooltipOpts =
    typeof viewConfig.eventTooltip === "object" ? viewConfig.eventTooltip : null
  const tooltipContent =
    !preview && viewConfig.eventTooltip
      ? viewConfig.renderEventTooltip?.({
          occurrence,
          segment,
          view,
          label,
        }) || label
      : null
  const tooltipOn = Boolean(tooltipContent)

  const showResize =
    interactive && resizeOn && !event.readOnly && event.resizable !== false
  // Hover grip pill (mirrors the gantt bars): a tiny bar inside each resize
  // handle signals the direction. Shown on every resizable chip - compact
  // sub-compactEventMinutes timed blocks included - because the chip
  // min-height (1.5rem) leaves room at the very top/bottom edges without
  // colliding with the vertically-centered title.
  const grip = (
    <span
      aria-hidden
      data-slot="event-calendar-resize-grip"
      className={cn(
        "bg-foreground/40 rounded-full",
        timedBlock ? "h-0.5 w-2.5" : "h-2.5 w-0.5",
        viewConfig.classNames?.resizeGrip
      )}
    />
  )
  const resizeHandles = showResize && (
    <>
      {timedBlock && segment.isStart && (
        <span
          data-slot="event-calendar-resize-handle"
          data-edge="start"
          className={cn(
            "absolute inset-x-1 top-0 flex h-1.5 cursor-ns-resize items-center justify-center opacity-0 transition-opacity duration-150 group-hover/ec-event:opacity-100",
            viewConfig.classNames?.resizeHandle
          )}
          onPointerDown={(e) => gestures.beginResize(e, segment, "start")}
        >
          {grip}
        </span>
      )}
      {timedBlock && segment.isEnd && (
        <span
          data-slot="event-calendar-resize-handle"
          data-edge="end"
          className={cn(
            "absolute inset-x-1 bottom-0 flex h-1.5 cursor-ns-resize items-center justify-center opacity-0 transition-opacity duration-150 group-hover/ec-event:opacity-100",
            viewConfig.classNames?.resizeHandle
          )}
          onPointerDown={(e) => gestures.beginResize(e, segment, "end")}
        >
          {grip}
        </span>
      )}
      {(horizontalBar || (isBar && inTimeGrid)) && segment.isStart && (
        <span
          data-slot="event-calendar-resize-handle"
          data-edge="start"
          className={cn(
            "absolute inset-y-0 start-0 flex w-2 cursor-ew-resize items-center justify-center opacity-0 transition-opacity duration-150 group-hover/ec-event:opacity-100",
            viewConfig.classNames?.resizeHandle
          )}
          onPointerDown={(e) => gestures.beginResize(e, segment, "start")}
        >
          {grip}
        </span>
      )}
      {(horizontalBar || (isBar && inTimeGrid)) && segment.isEnd && (
        <span
          data-slot="event-calendar-resize-handle"
          data-edge="end"
          className={cn(
            "absolute inset-y-0 end-0 flex w-2 cursor-ew-resize items-center justify-center opacity-0 transition-opacity duration-150 group-hover/ec-event:opacity-100",
            viewConfig.classNames?.resizeHandle
          )}
          onPointerDown={(e) => gestures.beginResize(e, segment, "end")}
        >
          {grip}
        </span>
      )}
    </>
  )

  const defaultProps = {
    type: "button" as const,
    "data-slot": "event-calendar-event",
    "data-view": view,
    "data-all-day": occurrence.allDay || undefined,
    "data-recurring": occurrence.isRecurring || undefined,
    "data-selected": isSelected || undefined,
    "data-dragging": isDragging || undefined,
    "data-preview": preview || undefined,
    "data-past": occurrence.end.getTime() < Date.now() || undefined,
    // native hover reveal for squeezed/faded chips: full title + time (dropped
    // when the styled eventTooltip is on so the two never stack)
    title: preview || tooltipOn ? undefined : label,
    "aria-label":
      settings.i18n.functions.formatEventAriaLabel?.(
        event.title,
        timeLabel,
        segment.continuesBefore || segment.continuesAfter
      ) ??
      `${event.title}, ${timeLabel}${
        segment.continuesBefore || segment.continuesAfter
          ? `, ${settings.i18n.labels.continues}`
          : ""
      }`,
    "aria-hidden": preview || undefined,
    tabIndex: preview ? -1 : undefined,
    style: {
      "--ec-event-color": event.color ?? "var(--color-primary)",
    } as CSSProperties,
    onPointerDown: (e: React.PointerEvent) => {
      e.stopPropagation()
      // suppress the trailing slot-create click if this press does not turn
      // into a drag (e.g. a locked chip) - see markChipPress
      markChipPress()
      if (interactive) gestures.beginMove(e, segment)
    },
    onClick: (e: React.MouseEvent) => {
      e.stopPropagation()
      if (wasRecentDrag()) return
      // consumer first: e.preventDefault() opts out of built-in selection
      // (e.g. click = open dialog only, no selected tint)
      settings.onEventClick?.(occurrence, e)
      // the agenda is a read-only list: a click never selects/focuses a row
      if (e.defaultPrevented || view === "agenda") return
      instance.api.selectEvent(occurrence.key)
    },
    onDoubleClick: (e: React.MouseEvent) => {
      e.stopPropagation()
      settings.onEventDoubleClick?.(occurrence, e)
    },
    className: cn(
      "group/ec-event text-foreground relative flex w-full min-w-0 cursor-pointer touch-none items-center overflow-hidden text-start select-none",
      "focus-visible:ring-ring/50 outline-none focus-visible:ring-2",
      preview && "pointer-events-none",
      view === "agenda"
        ? // plain list row: color lives in the dot badge, not a tinted pill;
          // hover AND selection surfaces are owned by the agenda row wrapper
          "gap-3 rounded-md text-sm"
        : cn(
            // @container removes intrinsic sizing; only grid chips are containers
            // py-1: room above/below inline badges (attendee pill etc.)
            "@container gap-1.5 rounded-sm px-1.5 py-1 leading-normal",
            // soft tint + hairline inset ring: color reads from the surface
            // itself (no accent border), stays legible in light and dark
            "bg-(--ec-event-color)/15 hover:bg-(--ec-event-color)/25",
            // a flat tint reads darker over a dark surface, so lift it a little
            // in dark mode to keep a lighter, softer chip tone
            "dark:bg-(--ec-event-color)/20 dark:hover:bg-(--ec-event-color)/30",
            "inset-ring inset-ring-(--ec-event-color)/15",
            "transition-[background-color,box-shadow] duration-150",
            "data-dragging:opacity-40",
            "data-selected:bg-(--ec-event-color)/30 data-selected:inset-ring-(--ec-event-color)/40",
            segment.continuesBefore && "rounded-s-none",
            segment.continuesAfter && "rounded-e-none"
          ),
      viewConfig.classNames?.event,
      className
    ),
    children: (
      <>
        {content}
        {resizeHandles}
      </>
    ),
  }

  const chip = useRender({
    defaultTagName: "button",
    render,
    props: mergeProps<"button">(defaultProps, props),
  })

  return (
    <EventCalendarChipContext.Provider
      value={{ occurrence, segment, isDragging, isSelected }}
    >
      {tooltipOn ? (
        <TooltipProvider delay={tooltipOpts?.delay ?? 600}>
          <Tooltip>
            <TooltipTrigger render={chip} />
            <TooltipContent
              side={tooltipOpts?.side ?? "top"}
              className={viewConfig.classNames?.eventTooltip}
            >
              {tooltipContent}
            </TooltipContent>
          </Tooltip>
        </TooltipProvider>
      ) : (
        chip
      )}
    </EventCalendarChipContext.Provider>
  )
}

export {
  EVENT_CALENDAR_COLORS,
  EVENT_CALENDAR_FADE_TRUNCATE,
  EVENT_CALENDAR_GHOST,
  EventCalendarEvent,
  useEventCalendarEventChip,
}
export type { EventCalendarChipContextValue, EventCalendarEventProps }

// Title: Event Calendar I18n
// Description: Default UI texts, date-format strings, and formatter functions for the event calendar, fully overridable per key.

import type {
  CalendarView,
  EventCalendarDateRange,
} from "@/components/reui/event-calendar/event-calendar-types"
import { format, isSameMonth, isSameYear, type Locale } from "date-fns"

interface EventCalendarI18nConfig {
  labels: {
    today: string
    previous: string
    next: string
    addEvent: string
    allDay: string
    more: (count: number) => string
    noEvents: string
    loading: string
    event: string
    events: (count: number) => string
    selectView: string
    week: (weekNumber: number) => string
    resources: string
    goToDate: string
    /** Cursor hint while a drag/resize hovers a rejected position. */
    dropNotAllowed: string
    /** Aria-label suffix on chip segments that continue past the cell. */
    continues: string
    /** Agenda label for the first day of a multi-day event. */
    timeFrom: (time: string) => string
    /** Agenda label for the last day of a multi-day event. */
    timeUntil: (time: string) => string
    /** View-switcher shortcut hint characters, per view. */
    viewShortcuts: Record<CalendarView, string>
    /** Aria-label of the agenda day collapse/expand toggle. */
    toggleDayEvents: (count: number, expanded: boolean) => string
    /** Aria-label of the agenda event details toggle. */
    eventDetails: (title: string) => string
    /** Compact "+N" overflow (agenda summary dot stack). */
    moreCompact: (count: number) => string
    /** Joins a bounded from-to time span. */
    timeRange: (from: string, to: string) => string
  }
  viewNames: {
    month: string
    week: string
    day: string
    days: (count: number) => string
    agenda: string
    resource: string
  }
  /** date-fns format strings, applied with the calendar `locale`. */
  formats: {
    monthTitle: string
    /** Undefined = smart cross-month range via functions.formatTitle. */
    weekTitle?: string
    dayTitle: string
    /** Undefined = smart range label via functions.formatTitle. */
    agendaTitle?: string
    monthDayHeader: string
    /** Narrow variant used by the month view below the compact breakpoint. */
    monthDayHeaderNarrow: string
    timeGridDayHeader: string
    agendaDayHeader: string
    /** Agenda date-gutter day number. */
    agendaDayNumber: string
    /** Agenda date-gutter weekday label. */
    agendaWeekday: string
    /** "+N more" popover day header. */
    moreDayHeader: string
    /** Month cell aria-label date. */
    monthCellAriaLabel: string
    /** Time-grid day column aria-label date. */
    dayAria: string
    /** Undefined = the resource view title falls back to dayTitle. */
    resourceTitle?: string
    timeGutter: string
    /** Sub-hour gutter labels (interval below 60 minutes). */
    timeGutterMinute: string
    eventTime: string
    monthCellDay: string
  }
  functions: {
    formatTitle: (
      view: CalendarView,
      ctx: {
        date: Date
        activeRange: EventCalendarDateRange
        visibleRange: EventCalendarDateRange
        locale?: Locale
      }
    ) => string
    formatEventTime: (start: Date, end: Date, allDay: boolean) => string
    formatDayRange: (range: EventCalendarDateRange) => string
    /** Chip native tooltip text; return undefined to drop the attribute. */
    formatEventLabel?: (title: string, timeLabel: string) => string | undefined
    /** Chip aria-label composition. */
    formatEventAriaLabel?: (
      title: string,
      timeLabel: string,
      continues: boolean
    ) => string
  }
}

const DEFAULT_LABELS: EventCalendarI18nConfig["labels"] = {
  today: "Today",
  previous: "Previous",
  next: "Next",
  addEvent: "Add event",
  allDay: "All day",
  more: (count) => `+${count} more`,
  noEvents: "No events",
  loading: "Loading events",
  event: "event",
  events: (count) => (count === 1 ? "1 event" : `${count} events`),
  selectView: "Select view",
  week: (weekNumber) => `W${weekNumber}`,
  resources: "Resources",
  goToDate: "Go to date",
  dropNotAllowed: "Can't place here",
  continues: "continues",
  timeFrom: (time) => `From ${time}`,
  timeUntil: (time) => `Until ${time}`,
  viewShortcuts: {
    month: "M",
    week: "W",
    day: "D",
    days: "5",
    agenda: "A",
    resource: "G",
  },
  toggleDayEvents: (count) => (count === 1 ? "1 event" : `${count} events`),
  eventDetails: (title) => title,
  moreCompact: (count) => `+${count}`,
  timeRange: (from, to) => `${from} - ${to}`,
}

const DEFAULT_VIEW_NAMES: EventCalendarI18nConfig["viewNames"] = {
  month: "Month",
  week: "Week",
  day: "Day",
  days: (count) => `${count} days`,
  agenda: "Agenda",
  resource: "Time Grid",
}

const DEFAULT_FORMATS: EventCalendarI18nConfig["formats"] = {
  monthTitle: "MMMM yyyy",
  weekTitle: undefined,
  dayTitle: "EEEE, MMMM d, yyyy",
  agendaTitle: undefined,
  monthDayHeader: "EEE",
  monthDayHeaderNarrow: "EEEEE",
  timeGridDayHeader: "EEE d",
  agendaDayHeader: "EEEE, MMMM d",
  agendaDayNumber: "d",
  agendaWeekday: "EEE",
  moreDayHeader: "EEEE, MMMM d",
  monthCellAriaLabel: "PPPP",
  dayAria: "PPPP",
  resourceTitle: undefined,
  timeGutter: "h a",
  timeGutterMinute: "h:mm a",
  eventTime: "h:mm a",
  monthCellDay: "d",
}

/**
 * Default formatting functions BOUND to a config's labels/formats, so that
 * `formats` overrides flow into the default renderers (a consumer overriding
 * formats.monthTitle without replacing formatTitle still sees it applied).
 */
function makeDefaultFunctions(
  cfg: Pick<EventCalendarI18nConfig, "labels" | "formats">
): EventCalendarI18nConfig["functions"] {
  return {
    formatTitle: (view, { date, activeRange, locale }) => {
      const opts = { locale }
      if (view === "month") {
        return format(date, cfg.formats.monthTitle, opts)
      }
      if (view === "resource") {
        return format(
          date,
          cfg.formats.resourceTitle ?? cfg.formats.dayTitle,
          opts
        )
      }
      if (view === "day") {
        return format(date, cfg.formats.dayTitle, opts)
      }
      if (view === "week" && cfg.formats.weekTitle) {
        return format(date, cfg.formats.weekTitle, opts)
      }
      if (view === "agenda" && cfg.formats.agendaTitle) {
        return format(date, cfg.formats.agendaTitle, opts)
      }
      // week / days / agenda: smart range label, last day is activeRange.end - 1ms
      const rangeEnd = new Date(activeRange.end.getTime() - 1)
      const start = activeRange.start
      if (isSameMonth(start, rangeEnd)) {
        return `${format(start, "MMMM d", opts)} - ${format(rangeEnd, "d, yyyy", opts)}`
      }
      if (isSameYear(start, rangeEnd)) {
        return `${format(start, "MMM d", opts)} - ${format(rangeEnd, "MMM d, yyyy", opts)}`
      }
      return `${format(start, "MMM d, yyyy", opts)} - ${format(rangeEnd, "MMM d, yyyy", opts)}`
    },
    formatEventTime: (start, end, allDay) => {
      if (allDay) return cfg.labels.allDay
      const fmt = cfg.formats.eventTime
      // Multi-day timed events carry the date on both sides
      if (end.getTime() - start.getTime() > 24 * 60 * 60 * 1000) {
        return `${format(start, `MMM d, ${fmt}`)} - ${format(end, `MMM d, ${fmt}`)}`
      }
      return `${format(start, fmt)} - ${format(end, fmt)}`
    },
    formatDayRange: (range) => {
      const rangeEnd = new Date(range.end.getTime() - 1)
      return `${format(range.start, "MMM d")} - ${format(rangeEnd, "MMM d")}`
    },
  }
}

const DEFAULT_EVENT_CALENDAR_I18N: EventCalendarI18nConfig = {
  labels: DEFAULT_LABELS,
  viewNames: DEFAULT_VIEW_NAMES,
  formats: DEFAULT_FORMATS,
  functions: makeDefaultFunctions({
    labels: DEFAULT_LABELS,
    formats: DEFAULT_FORMATS,
  }),
}

/**
 * Shallow merge per nested object, matching the filters.tsx i18n contract:
 * a partial override replaces individual keys, never whole sections. Default
 * functions are re-bound to the MERGED labels/formats; explicit `functions`
 * overrides still win.
 */
function mergeEventCalendarI18n(
  overrides?: Partial<EventCalendarI18nConfig>
): EventCalendarI18nConfig {
  if (!overrides) return DEFAULT_EVENT_CALENDAR_I18N
  const labels = { ...DEFAULT_LABELS, ...overrides.labels }
  const viewNames = { ...DEFAULT_VIEW_NAMES, ...overrides.viewNames }
  const formats = { ...DEFAULT_FORMATS, ...overrides.formats }
  return {
    labels,
    viewNames,
    formats,
    functions: {
      ...makeDefaultFunctions({ labels, formats }),
      ...overrides.functions,
    },
  }
}

export { DEFAULT_EVENT_CALENDAR_I18N, mergeEventCalendarI18n }
export type { EventCalendarI18nConfig }

// Title: Event Calendar Lib
// Description: Pure, React-free calendar math: view ranges, zoned day keys, multi-day segmentation, overlap packing, lane packing, and the event index.

import { expandRecurrence } from "@/components/reui/event-calendar/event-calendar-recurrence"
import type {
  CalendarEvent,
  CalendarView,
  EventCalendarDateRange,
  EventCalendarOccurrence,
  EventCalendarOffDaysConfig,
  EventCalendarResource,
  EventCalendarSegment,
} from "@/components/reui/event-calendar/event-calendar-types"
import { TZDate } from "@date-fns/tz"
import {
  addDays,
  addMonths,
  addWeeks,
  differenceInCalendarDays,
  differenceInMinutes,
  format,
  startOfDay,
  startOfMonth,
  startOfWeek,
} from "date-fns"

type WeekStartsOn = 0 | 1 | 2 | 3 | 4 | 5 | 6

/** Packing-effective minimum in minutes so tiny events do not stack invisibly. */
const MIN_PACK_SLOT = 30

/** The instant re-expressed in the display time zone (TZDate extends Date). */
function toZoned(date: Date, timeZone: string): TZDate {
  return new TZDate(date.getTime(), timeZone)
}

/** Zoned midnight of the day containing the instant. */
function zonedStartOfDay(date: Date, timeZone: string): TZDate {
  return startOfDay(toZoned(date, timeZone))
}

/** Stable per-day key in the display time zone. */
function getDayKey(date: Date, timeZone: string): string {
  return format(toZoned(date, timeZone), "yyyy-MM-dd")
}

/** Day length in minutes; 1380/1500 on DST transition days - never assume 1440. */
function getDayTotalMinutes(dayStart: Date, timeZone: string): number {
  const next = zonedStartOfDay(
    addDays(toZoned(dayStart, timeZone), 1),
    timeZone
  )
  return differenceInMinutes(next, dayStart)
}

function snapMinutes(minutes: number, snap: number): number {
  return Math.round(minutes / snap) * snap
}

interface ViewRangeOptions {
  timeZone: string
  weekStartsOn: WeekStartsOn
  dayCount: number
  agendaDayCount: number
  fixedWeeks: boolean
}

interface ViewDateRanges {
  visibleRange: EventCalendarDateRange
  activeRange: EventCalendarDateRange
}

function getViewDateRange(
  view: CalendarView,
  date: Date,
  opts: ViewRangeOptions
): ViewDateRanges {
  const { timeZone, weekStartsOn, dayCount, agendaDayCount, fixedWeeks } = opts
  const zoned = toZoned(date, timeZone)

  if (view === "month") {
    const activeStart = startOfMonth(zoned)
    const activeEnd = startOfMonth(addMonths(zoned, 1))
    const visibleStart = startOfWeek(activeStart, { weekStartsOn })
    let visibleEnd: Date
    if (fixedWeeks) {
      visibleEnd = addDays(visibleStart, 42)
    } else {
      visibleEnd = startOfWeek(addDays(activeEnd, -1), { weekStartsOn })
      visibleEnd = addWeeks(visibleEnd, 1)
    }
    return {
      activeRange: { start: activeStart, end: activeEnd },
      visibleRange: { start: visibleStart, end: visibleEnd },
    }
  }

  if (view === "week") {
    const start = startOfWeek(zoned, { weekStartsOn })
    const range = { start, end: addWeeks(start, 1) }
    return { activeRange: range, visibleRange: range }
  }

  if (view === "day" || view === "resource") {
    const start = startOfDay(zoned)
    const range = { start, end: addDays(start, 1) }
    return { activeRange: range, visibleRange: range }
  }

  if (view === "days") {
    const start = startOfDay(zoned)
    const range = { start, end: addDays(start, Math.max(1, dayCount)) }
    return { activeRange: range, visibleRange: range }
  }

  // agenda
  const start = startOfDay(zoned)
  const range = { start, end: addDays(start, Math.max(1, agendaDayCount)) }
  return { activeRange: range, visibleRange: range }
}

/** The anchor date stepped one period forward or backward for the view. */
function stepDate(
  view: CalendarView,
  date: Date,
  direction: 1 | -1,
  opts: Pick<ViewRangeOptions, "timeZone" | "dayCount" | "agendaDayCount">
): Date {
  const zoned = toZoned(date, opts.timeZone)
  if (view === "month") return addMonths(zoned, direction)
  if (view === "week") return addWeeks(zoned, direction)
  if (view === "day" || view === "resource") return addDays(zoned, direction)
  if (view === "days")
    return addDays(zoned, direction * Math.max(1, opts.dayCount))
  return addDays(zoned, direction * Math.max(1, opts.agendaDayCount))
}

function rangesIntersect(
  a: EventCalendarDateRange,
  b: EventCalendarDateRange
): boolean {
  return a.start < b.end && a.end > b.start
}

function eventsOverlap(
  a: { start: Date; end: Date },
  b: { start: Date; end: Date }
): boolean {
  return a.start < b.end && a.end > b.start
}

/**
 * The one canonical multi-day segmentation. Splits an occurrence into per-day
 * segments clamped to the range. Rules (unit-tested in M1): exclusive end - an
 * event ending exactly at zoned midnight emits NO segment for that day;
 * zero-duration events emit one min-height segment; allDay compares date-only
 * in the display zone.
 */
function segmentOccurrence<TData>(
  occurrence: EventCalendarOccurrence<TData>,
  range: EventCalendarDateRange,
  timeZone: string
): EventCalendarSegment<TData>[] {
  const occStart = occurrence.start
  const occEnd = occurrence.end
  const isZeroLength = occEnd.getTime() === occStart.getTime()

  const clampStart = occStart > range.start ? occStart : range.start
  const clampEnd = occEnd < range.end ? occEnd : range.end
  if (clampEnd < clampStart) return []
  if (clampEnd.getTime() === clampStart.getTime() && !isZeroLength) return []

  const segments: EventCalendarSegment<TData>[] = []
  let cursor = zonedStartOfDay(clampStart, timeZone)

  while (cursor < clampEnd || (isZeroLength && segments.length === 0)) {
    const next = zonedStartOfDay(
      addDays(toZoned(cursor, timeZone), 1),
      timeZone
    )
    const segStart = clampStart > cursor ? clampStart : cursor
    const segEnd = clampEnd < next ? clampEnd : next

    const emptySeg = segEnd.getTime() <= segStart.getTime()
    if (!emptySeg || isZeroLength) {
      const isStart = segStart.getTime() === occStart.getTime()
      const isEnd = segEnd.getTime() === occEnd.getTime()
      segments.push({
        occurrence,
        day: cursor,
        isStart,
        isEnd,
        continuesBefore: !isStart,
        continuesAfter: !isEnd,
        startMin: occurrence.allDay
          ? undefined
          : differenceInMinutes(segStart, cursor),
        endMin: occurrence.allDay
          ? undefined
          : Math.max(
              differenceInMinutes(segEnd, cursor),
              differenceInMinutes(segStart, cursor)
            ),
      })
    }
    if (isZeroLength) break
    cursor = next
  }

  return segments
}

/** True when the occurrence should render as a bar (all-day row / month lanes). */
function isBarOccurrence(occurrence: EventCalendarOccurrence): boolean {
  return occurrence.allDay || spansMultipleDays(occurrence)
}

function spansMultipleDays(occ: { start: Date; end: Date }): boolean {
  // An event ending exactly at the next midnight is still single-day
  // (exclusive end), so compare against a strictly-later instant.
  return occ.end.getTime() - occ.start.getTime() > 24 * 60 * 60 * 1000
}

interface PackedPosition {
  column: number
  columnCount: number
  columnSpan: number
}

/**
 * Google-style overlap packing for one day's timed segments.
 * Mutates column/columnCount/columnSpan on the segments, in place.
 * z resolution happens at render: event.zIndex verbatim, else 10 + column.
 */
function packTimedSegments<TData>(
  segments: EventCalendarSegment<TData>[]
): void {
  if (segments.length === 0) return

  type Working = {
    seg: EventCalendarSegment<TData>
    startMin: number
    effEnd: number
  }

  const items: Working[] = segments
    .map((seg) => {
      const startMin = seg.startMin ?? 0
      const endMin = seg.endMin ?? startMin
      return {
        seg,
        startMin,
        effEnd: Math.max(endMin, startMin + MIN_PACK_SLOT),
      }
    })
    .sort(
      (a, b) =>
        a.startMin - b.startMin ||
        b.effEnd - b.startMin - (a.effEnd - a.startMin) ||
        a.seg.occurrence.key.localeCompare(b.seg.occurrence.key)
    )

  // Sweep into connected clusters
  const clusters: Working[][] = []
  let current: Working[] = []
  let clusterEnd = -Infinity
  for (const item of items) {
    if (item.startMin >= clusterEnd) {
      current = []
      clusters.push(current)
      clusterEnd = -Infinity
    }
    current.push(item)
    clusterEnd = Math.max(clusterEnd, item.effEnd)
  }

  for (const cluster of clusters) {
    // Greedy column assignment
    const colEnds: number[] = []
    const byColumn = new Map<number, Working[]>()
    for (const item of cluster) {
      let col = colEnds.findIndex((end) => end <= item.startMin)
      if (col === -1) {
        col = colEnds.length
        colEnds.push(0)
      }
      colEnds[col] = item.effEnd
      item.seg.column = col
      const bucket = byColumn.get(col) ?? []
      bucket.push(item)
      byColumn.set(col, bucket)
    }
    const columnCount = colEnds.length

    // Partial-overlap expansion: widen rightward into free columns
    for (const item of cluster) {
      let span = 1
      const col = item.seg.column ?? 0
      while (col + span < columnCount) {
        const occupants = byColumn.get(col + span) ?? []
        const blocked = occupants.some(
          (o) => o.startMin < item.effEnd && o.effEnd > item.startMin
        )
        if (blocked) break
        span++
      }
      item.seg.columnCount = columnCount
      item.seg.columnSpan = span
    }
  }
}

/**
 * Greedy lane packing for bar segments within one week row (7 columns).
 * Mutates lane/rowIndex/colStart/colSpan on the segments, in place.
 */
/**
 * Build the laned month-row bars for one week: consecutive-day segments of
 * the same occurrence merge into ONE bar (colStart -> colSpan) stacked into
 * lanes. Returns NEW segment objects - the shared per-day segments (also
 * rendered by the all-day rows and day cells) must stay pristine: mutating
 * their isEnd/continues flags gave the first-day chip a whole-bar shape and
 * a bogus end resize handle in the week all-day row, where dragging it
 * collapsed the event to a single day.
 */
function packWeekRowLanes<TData>(
  segments: EventCalendarSegment<TData>[],
  rowIndex: number,
  rowStart: Date,
  timeZone: string
): EventCalendarSegment<TData>[] {
  type Bar = {
    seg: EventCalendarSegment<TData>
    colStart: number
    colSpan: number
    isStart: boolean
    isEnd: boolean
    lane: number
  }

  const bars: Bar[] = segments.map((seg) => {
    const dayIndex = Math.round(
      (zonedStartOfDay(seg.day, timeZone).getTime() -
        zonedStartOfDay(rowStart, timeZone).getTime()) /
        (24 * 60 * 60 * 1000)
    )
    return {
      seg,
      colStart: Math.max(0, Math.min(6, dayIndex)),
      colSpan: 1,
      isStart: seg.isStart,
      isEnd: seg.isEnd,
      lane: 0,
    }
  })

  // Merge consecutive-day segments of the same occurrence into one bar per row
  const merged = new Map<string, Bar>()
  for (const bar of bars) {
    const key = bar.seg.occurrence.key
    const existing = merged.get(key)
    if (existing) {
      const start = Math.min(existing.colStart, bar.colStart)
      const end = Math.max(
        existing.colStart + existing.colSpan,
        bar.colStart + bar.colSpan
      )
      existing.colStart = start
      existing.colSpan = end - start
      existing.isStart = existing.isStart || bar.isStart
      existing.isEnd = existing.isEnd || bar.isEnd
    } else {
      merged.set(key, bar)
    }
  }

  const rowBars = Array.from(merged.values()).sort(
    (a, b) =>
      a.colStart - b.colStart ||
      b.colSpan - a.colSpan ||
      a.seg.occurrence.key.localeCompare(b.seg.occurrence.key)
  )

  const lanes: boolean[][] = []
  for (const bar of rowBars) {
    let lane = 0
    for (;;) {
      lanes[lane] ??= new Array(7).fill(false)
      const row = lanes[lane]
      let free = true
      for (let c = bar.colStart; c < bar.colStart + bar.colSpan; c++) {
        if (row[c]) {
          free = false
          break
        }
      }
      if (free) break
      lane++
    }
    for (let c = bar.colStart; c < bar.colStart + bar.colSpan; c++) {
      lanes[lane][c] = true
    }
    bar.lane = lane
  }

  return rowBars.map((bar) => ({
    ...bar.seg,
    isStart: bar.isStart,
    isEnd: bar.isEnd,
    continuesBefore: !bar.isStart,
    continuesAfter: !bar.isEnd,
    lane: bar.lane,
    rowIndex,
    colStart: bar.colStart,
    colSpan: bar.colSpan,
  }))
}

interface EventCalendarDayBucket<TData = unknown> {
  allDay: EventCalendarSegment<TData>[]
  timed: EventCalendarSegment<TData>[]
}

interface EventCalendarWeekRow<TData = unknown> {
  rowIndex: number
  rowStart: Date
  /** Laned bar segments (one per occurrence per row). */
  bars: EventCalendarSegment<TData>[]
}

interface EventCalendarIndex<TData = unknown> {
  occurrences: EventCalendarOccurrence<TData>[]
  byDay: Map<string, EventCalendarDayBucket<TData>>
  weekRows: EventCalendarWeekRow<TData>[]
}

interface BuildIndexOptions<TData> {
  timeZone: string
  weekStartsOn: WeekStartsOn
  eventOrder?: (
    a: EventCalendarOccurrence<TData>,
    b: EventCalendarOccurrence<TData>
  ) => number
  getOccurrences?: (
    event: CalendarEvent<TData>,
    range: EventCalendarDateRange,
    ctx: { timeZone: string }
  ) => Array<{ start: Date; end: Date }> | null
}

function defaultEventOrder(
  a: EventCalendarOccurrence,
  b: EventCalendarOccurrence
): number {
  return (
    a.start.getTime() - b.start.getTime() ||
    b.end.getTime() -
      b.start.getTime() -
      (a.end.getTime() - a.start.getTime()) ||
    a.key.localeCompare(b.key)
  )
}

function buildEventIndex<TData>(
  events: CalendarEvent<TData>[],
  visibleRange: EventCalendarDateRange,
  opts: BuildIndexOptions<TData>
): EventCalendarIndex<TData> {
  const { timeZone, weekStartsOn } = opts
  const order = opts.eventOrder ?? defaultEventOrder

  // RECURRENCE-ID override replacement: an event carrying recurringEventId +
  // originalStart is an edited single occurrence of that series. The parent's
  // expansion drops the replaced instant; the override renders as its own
  // occurrence through the normal path below.
  const overrideTimes = new Map<string, Set<number>>()
  for (const event of events) {
    if (!event.recurringEventId || !event.originalStart) continue
    let times = overrideTimes.get(event.recurringEventId)
    if (!times) overrideTimes.set(event.recurringEventId, (times = new Set()))
    times.add(event.originalStart.getTime())
  }

  const occurrences: EventCalendarOccurrence<TData>[] = []
  for (const event of events) {
    const custom = opts.getOccurrences?.(event, visibleRange, { timeZone })
    if (custom) {
      custom.forEach((occ, i) => {
        if (!rangesIntersect({ start: occ.start, end: occ.end }, visibleRange))
          return
        occurrences.push({
          key: `${event.id}::${occ.start.toISOString()}`,
          eventId: event.id,
          event,
          start: occ.start,
          end: occ.end,
          allDay: event.allDay ?? false,
          isRecurring: true,
          recurrenceIndex: i,
        })
      })
      continue
    }
    const replaced = overrideTimes.get(event.id)
    const expanded = expandRecurrence(event, visibleRange, { timeZone })
    occurrences.push(
      ...(replaced
        ? expanded.filter((occ) => !replaced.has(occ.start.getTime()))
        : expanded)
    )
  }
  occurrences.sort(order)

  const byDay = new Map<string, EventCalendarDayBucket<TData>>()
  const barSegmentsByRow = new Map<number, EventCalendarSegment<TData>[]>()
  const firstRowStart = startOfWeek(toZoned(visibleRange.start, timeZone), {
    weekStartsOn,
  })

  for (const occurrence of occurrences) {
    const segments = segmentOccurrence(occurrence, visibleRange, timeZone)
    const bar = isBarOccurrence(occurrence)
    for (const seg of segments) {
      const key = getDayKey(seg.day, timeZone)
      let bucket = byDay.get(key)
      if (!bucket) {
        bucket = { allDay: [], timed: [] }
        byDay.set(key, bucket)
      }
      if (bar) {
        bucket.allDay.push(seg)
        // calendar-day math, not a fixed 168h divisor: DST transition weeks
        // are 167/169h long and the fixed divisor mis-buckets every later
        // Sunday one row early (which then clamps into the wrong column)
        const rowIndex = Math.floor(
          differenceInCalendarDays(toZoned(seg.day, timeZone), firstRowStart) /
            7
        )
        const rowBucket = barSegmentsByRow.get(rowIndex) ?? []
        rowBucket.push(seg)
        barSegmentsByRow.set(rowIndex, rowBucket)
      } else {
        bucket.timed.push(seg)
      }
    }
  }

  for (const bucket of byDay.values()) {
    packTimedSegments(bucket.timed)
  }

  const weekRows: EventCalendarWeekRow<TData>[] = []
  for (const [rowIndex, segs] of barSegmentsByRow) {
    const rowStart = addWeeks(firstRowStart, rowIndex)
    weekRows.push({
      rowIndex,
      rowStart,
      bars: packWeekRowLanes(segs, rowIndex, rowStart, timeZone),
    })
  }
  weekRows.sort((a, b) => a.rowIndex - b.rowIndex)

  return { occurrences, byDay, weekRows }
}

/** Cache key for index memoization; cheap string compare. */
function getRangeKey(range: EventCalendarDateRange): string {
  return `${range.start.getTime()}-${range.end.getTime()}`
}

/** Depth-first flatten of the resource tree (parents included). */
function flattenResources(
  resources: EventCalendarResource[],
  depth = 0
): Array<{ resource: EventCalendarResource; depth: number }> {
  const rows: Array<{ resource: EventCalendarResource; depth: number }> = []
  for (const resource of resources) {
    rows.push({ resource, depth })
    if (resource.children?.length) {
      rows.push(...flattenResources(resource.children, depth + 1))
    }
  }
  return rows
}

const DEFAULT_WEEKEND_DAYS = [0, 6]

/** Resolves whether a day is an off day (non-working) in the display zone. */
function resolveOffDay(
  day: Date,
  timeZone: string,
  config: boolean | EventCalendarOffDaysConfig | undefined
): boolean {
  if (!config) return false
  const resolved: EventCalendarOffDaysConfig = config === true ? {} : config
  const weekendDays = resolved.weekendDays ?? DEFAULT_WEEKEND_DAYS
  const zoned = toZoned(day, timeZone)
  if (weekendDays.includes(zoned.getDay())) return true
  if (resolved.dates?.length) {
    const key = getDayKey(day, timeZone)
    if (resolved.dates.some((date) => getDayKey(date, timeZone) === key)) {
      return true
    }
  }
  return resolved.isOffDay?.(day) ?? false
}

export {
  buildEventIndex,
  defaultEventOrder,
  eventsOverlap,
  flattenResources,
  getDayKey,
  getDayTotalMinutes,
  getRangeKey,
  getViewDateRange,
  isBarOccurrence,
  MIN_PACK_SLOT,
  packTimedSegments,
  packWeekRowLanes,
  rangesIntersect,
  resolveOffDay,
  segmentOccurrence,
  snapMinutes,
  spansMultipleDays,
  stepDate,
  toZoned,
  zonedStartOfDay,
}
export type {
  BuildIndexOptions,
  EventCalendarDayBucket,
  EventCalendarIndex,
  EventCalendarWeekRow,
  ViewDateRanges,
  ViewRangeOptions,
  WeekStartsOn,
}

// Title: Event Calendar Month View
// Description: ARIA-grid month view with week rows, day cells, event chips, and overflow counts.

"use client"

import {
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
  type CSSProperties,
  type Ref,
} from "react"
import {
  EventCalendarViewContext,
  useEventCalendar,
  useEventCalendarDay,
  useEventCalendarSelector,
  useEventCalendarSettings,
  useEventCalendarViewConfig,
  useEventCalendarViewSettings,
  useEventCalendarWeek,
} from "@/components/reui/event-calendar/event-calendar"
import {
  useEventCalendarGestures,
  wasRecentChipPress,
  wasRecentDrag,
} from "@/components/reui/event-calendar/event-calendar-dnd"
import {
  EVENT_CALENDAR_GHOST,
  EventCalendarEvent,
} from "@/components/reui/event-calendar/event-calendar-event"
import {
  getDayKey,
  getRangeKey,
  resolveOffDay,
  toZoned,
  zonedStartOfDay,
} from "@/components/reui/event-calendar/event-calendar-lib"
import type {
  EventCalendarDateRange,
  EventCalendarDragState,
  EventCalendarSegment,
} from "@/components/reui/event-calendar/event-calendar-types"
import { mergeProps } from "@base-ui/react/merge-props"
import { useRender } from "@base-ui/react/use-render"
import { addDays, format, getWeek } from "date-fns"

import { cn } from "@/lib/utils"
import {
